"use strict";const t=require("./config.js").STATIC_BASE_URL;exports.getImageUrl=(s,r=!0)=>{if(!s)return"";const e=String(s).trim();if(!e)return"";let i="";i=e.startsWith("http://")||e.startsWith("https://")?e:e.startsWith("/uploads/")?`${t}${e}`:e.startsWith("uploads/")?`${t}/${e}`:`${t}${e.startsWith("/")?e:"/"+e}`;try{const s=new URL(t),r=`${s.protocol}//${s.host}`;i=i.replace(/^https?:\/\/localhost(?::\d+)?/i,r).replace(/^https?:\/\/127\.0\.0\.1(?::\d+)?/i,r)}catch(o){}if(r&&i.includes(t)){const t=i.includes("?")?"&":"?";i=`${i}${t}_t=${Date.now()}`}return i};
